const crypto = require('crypto');
const secret = $vars.FUB_WEBHOOK_SECRET ?? '';
const sig = $input.first().json.headers?.['x-fub-signature'] ?? '';
if (secret && sig) {
  const body = JSON.stringify($input.first().json.body);
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');
  if (sig !== expected) throw new Error('Invalid FUB signature — request rejected');
}
function esc(s) { return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }
const rawEmail = $input.first().json.body?.agent?.email ?? $input.first().json.agent?.email ?? '';
const agentEmail = /^[^@]+@(anchorgroup\.com|theanchorgroup\.com|gmail\.com)$/i.test(rawEmail) ? rawEmail : '';
const b = $input.first().json.body ?? $input.first().json;
return [{ json: {
  address: esc(b.property?.address ?? b.deal?.property?.address ?? 'Address TBD'),
  city:    esc(b.property?.city    ?? b.deal?.property?.city    ?? 'Palm Coast'),
  price:   esc(b.property?.price   ?? b.deal?.value             ?? ''),
  beds:    esc(b.property?.bedrooms  ?? ''),
  baths:   esc(b.property?.bathrooms ?? ''),
  agent:   esc(b.agent?.name ?? 'the team'),
  agentEmail
}}];

const crypto = require('crypto');
const raw = $input.first().json.choices[0].message.content;
const prev = $('Verify FUB Signature + Sanitize').first().json;
function extract(label) {
  const regex = new RegExp(label + ':?\\s*([\\s\\S]*?)(?=(?:CELEBRATORY:|GRATEFUL:|$))', 'i');
  const m = raw.match(regex); return m ? m[1].trim() : '';
}
const drafts = [
  { tone: 'Celebratory', content: extract('CELEBRATORY') },
  { tone: 'Grateful',    content: extract('GRATEFUL') }
].filter(d => d.content);
return drafts.map(d => ({ json: {
  token: crypto.randomUUID(),
  workflow: 'sold',
  tone: d.tone,
  content: d.content,
  address: prev.address,
  city: prev.city,
  agent: prev.agent,
  agentEmail: prev.agentEmail
}}));

const token = $input.first().json.query?.token ?? '';
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(token)) {
  throw new Error('Invalid token format');
}
return [{ json: { token } }];

const row = $input.first().json;
if (!row || !row.id) return [{ json: { html: '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:sans-serif;text-align:center;padding:60px"><h2 style="color:#c00">Draft not found or expired.</h2></body></html>' } }];
function esc(s) { return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }
const tone = esc(row.tone);
const content = esc(row.content);
const id = esc(row.id);
const consumed = row.consumed;
const body = consumed
  ? '<p style="color:#c00;font-size:18px">This draft has already been published.</p>'
  : `<pre style="background:#f5f5f5;padding:16px;border-radius:6px;white-space:pre-wrap;font-family:inherit;margin:16px 0;font-size:15px">${content}</pre><form method="POST" action="https://n8n.joelycannoli.com/webhook/sold-post"><input type="hidden" name="token" value="${id}"/><button type="submit" style="background:#03466e;color:#fff;padding:12px 24px;border:none;border-radius:4px;font-size:16px;cursor:pointer">Confirm &amp; Post to Facebook</button></form>`;
return [{ json: { html: `<!DOCTYPE html><html><head><meta charset="utf-8"><meta http-equiv="Content-Security-Policy" content="default-src 'none'; style-src 'unsafe-inline'; form-action 'self' https://n8n.joelycannoli.com"><meta name="X-Content-Type-Options" content="nosniff"></head><body style="font-family:sans-serif;max-width:600px;margin:40px auto;padding:0 20px"><h2 style="color:#03466e">SOLD Post &mdash; ${tone} Tone</h2>${body}</body></html>` } }];

const token = $input.first().json.body?.token ?? '';
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(token)) {
  throw new Error('Invalid token format');
}
return [{ json: { token } }];
